get_prod_qc_name.body:
const dlms_config = window.__DLMS_CONFIG || {};

if (e?.data?.disabled__prod_qc) {
    return e?.data?.disabled__prod_qc;
}

// Guard: base URL must be present
if (!dlms_config.npBaseUrl) {
    console.error('[get_prod_qc_name] Missing npBaseUrl in window.__DLMS_CONFIG:', dlms_config);
    return;
}

const savedToken = localStorage.getItem('tokenv2') || localStorage.getItem('auth');

// Guard: token must be present
if (!savedToken) {
    console.error('[get_prod_qc_name] No auth token found in localStorage (tokenv2/auth)');
    return;
}

const url = `${dlms_config.npBaseUrl}/api/user-detail/`;
console.log('[get_prod_qc_name] Fetching user detail from:', url);

fetch(url, {
    method: 'GET',
    headers: {
        'accept': 'application/json',
        'authorization': `Token ${savedToken}`
    }
})
.then(res => {
    if (!res.ok) {
        throw new Error(`HTTP ${res.status} from ${url}`);
    }
    return res.json();
})
.then(userData => {
    if (userData?.name) {
        e.data.disabled__prod_qc = userData.name;
    } else {
        console.warn('[get_prod_qc_name] No name in response:', userData);
    }
})
.catch((error) => {
    console.error('[get_prod_qc_name] Fetch error:', error);
});

